import React, { useState, useEffect, useCallback } from 'react';
import { Link, useNavigate, useSearchParams } from 'react-router-dom';
import { datasetsApi } from '../services/api';

/* ─── Styles ──────────────────────────────────────────────────── */
const S = {
  page: { display: 'flex', minHeight: 'calc(100vh - 64px)', background: 'var(--color-bg)' },
  sidebar: {
    width: 260, flexShrink: 0, padding: '32px 24px',
    background: 'var(--color-surface)', borderRight: '1px solid var(--color-stone)',
    overflowY: 'auto',
  },
  sidebarTitle: { fontSize: 'var(--text-sm)', fontWeight: 'var(--weight-semibold)', color: 'var(--color-text-primary)', marginBottom: 20 },
  filterGroup: { marginBottom: 28 },
  filterLabel: {
    fontSize: 'var(--text-xs)', fontWeight: 'var(--weight-semibold)',
    letterSpacing: 'var(--tracking-wider)', textTransform: 'uppercase',
    color: 'var(--color-text-muted)', marginBottom: 10,
  },
  radio: { display: 'flex', alignItems: 'center', gap: 8, padding: '6px 0', cursor: 'pointer' },
  radioInput: { accentColor: 'var(--color-gold)', width: 14, height: 14, cursor: 'pointer' },
  radioLabel: { fontSize: 'var(--text-sm)', color: 'var(--color-text-secondary)', cursor: 'pointer', flex: 1 },
  radioCount: { fontSize: 'var(--text-xs)', color: 'var(--color-text-muted)' },
  select: {
    width: '100%', padding: '8px 12px', background: 'var(--color-bg)',
    border: '1px solid var(--color-stone)', borderRadius: 'var(--radius-md)',
    fontSize: 'var(--text-sm)', color: 'var(--color-text-primary)',
    cursor: 'pointer', outline: 'none',
  },
  rangeWrap: { padding: '4px 0' },
  range: { width: '100%', accentColor: 'var(--color-gold)' },
  rangeVal: { fontSize: 'var(--text-xs)', color: 'var(--color-gold)', fontWeight: 'var(--weight-semibold)' },
  /* Main */
  main: { flex: 1, padding: '32px', overflowX: 'hidden', minWidth: 0 },
  searchBar: {
    display: 'flex', alignItems: 'center', gap: 12,
    padding: '0 20px', background: '#fff',
    border: '2px solid var(--color-stone)', borderRadius: 'var(--radius-xl)',
    marginBottom: 28, transition: 'border-color 200ms, box-shadow 200ms',
  },
  searchInput: {
    flex: 1, padding: '14px 0', background: 'transparent', border: 'none',
    outline: 'none', fontSize: 'var(--text-base)', color: 'var(--color-text-primary)',
    fontFamily: 'var(--font-sans)',
  },
  searchIcon: { color: 'var(--color-text-muted)', fontSize: '1.1rem', flexShrink: 0 },
  meta: {
    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
    marginBottom: 20, flexWrap: 'wrap', gap: 8,
  },
  metaCount: { fontSize: 'var(--text-sm)', color: 'var(--color-text-muted)' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(280px,1fr))', gap: 18 },
  card: {
    background: '#fff', border: '1px solid var(--color-stone)',
    borderRadius: 'var(--radius-xl)', padding: '20px',
    transition: 'border-color 200ms, box-shadow 200ms, transform 200ms',
    display: 'flex', flexDirection: 'column', gap: 10, cursor: 'pointer',
  },
  cardTop: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' },
  cardName: { fontWeight: 'var(--weight-semibold)', color: 'var(--color-text-primary)', fontSize: 'var(--text-base)', lineHeight: 1.3 },
  cardCat: { fontSize: 'var(--text-xs)', color: 'var(--color-text-muted)', marginTop: 2 },
  cardDesc: {
    fontSize: 'var(--text-sm)', color: 'var(--color-text-muted)', lineHeight: 1.6,
    display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden',
  },
  cardStats: { display: 'flex', gap: 16, flexWrap: 'wrap' },
  cardStat: { fontSize: 'var(--text-xs)', color: 'var(--color-text-muted)', display: 'flex', alignItems: 'center', gap: 4 },
  cardTags: { display: 'flex', gap: 6, flexWrap: 'wrap' },
  qualDot: { width: 8, height: 8, borderRadius: '50%', display: 'inline-block' },
  pagination: { display: 'flex', gap: 6, justifyContent: 'center', marginTop: 40, flexWrap: 'wrap' },
  pageBtn: {
    width: 36, height: 36, borderRadius: 'var(--radius-md)', border: '1px solid var(--color-stone)',
    background: '#fff', cursor: 'pointer', fontSize: 'var(--text-sm)',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    color: 'var(--color-text-secondary)', transition: 'all 150ms',
  },
  pageBtnActive: {
    background: 'var(--color-dark)', color: '#fff', border: '1px solid var(--color-dark)',
  },
  empty: {
    textAlign: 'center', padding: '80px 20px',
    color: 'var(--color-text-muted)',
  },
};

const DOMAINS = ['All', 'Information Technology', 'Electronics', 'Healthcare', 'Geography', 'Sports'];
const SORT_OPTIONS = [
  { value: 'popularity', label: 'Most Popular' },
  { value: 'quality_score', label: 'Highest Quality' },
  { value: 'name', label: 'Name (A–Z)' },
  { value: 'record_count', label: 'Most Records' },
];
const DOMAIN_COLORS = {
  'Information Technology': 'var(--color-info)',
  'Electronics': 'var(--color-warning)',
  'Healthcare': 'var(--color-success)',
  'Geography': 'var(--color-emerald)',
  'Sports': '#9A4A2A',
};

function qualColor(score) {
  if (score >= 9) return '#2D7A5A';
  if (score >= 7) return '#9A6C2A';
  return '#8B2E2E';
}

function SkeletonCard() {
  return (
    <div style={{ ...S.card, cursor: 'default' }}>
      <div style={{ width: '70%', height: 18, borderRadius: 6 }} className="skeleton" />
      <div style={{ width: '40%', height: 12, borderRadius: 4 }} className="skeleton" />
      <div style={{ width: '100%', height: 48, borderRadius: 8 }} className="skeleton" />
      <div style={{ display: 'flex', gap: 8 }}>
        {[50, 70, 45].map((w, i) => <div key={i} style={{ width: w, height: 20, borderRadius: 99 }} className="skeleton" />)}
      </div>
    </div>
  );
}

export default function DataExplorer() {
  const navigate = useNavigate();
  const [params, setParams] = useSearchParams();

  const [datasets, setDatasets] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [domainCounts, setDomainCounts] = useState({});

  const [search, setSearch] = useState(params.get('q') || '');
  const [domain, setDomain] = useState(params.get('domain') || 'All');
  const [sortBy, setSortBy] = useState(params.get('sort') || 'popularity');
  const [minQuality, setMinQuality] = useState(Number(params.get('quality') || 0));
  const [page, setPage] = useState(Number(params.get('page') || 1));
  const PAGE_SIZE = 18;

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const res = await datasetsApi.list({
        search: search || undefined,
        domain: domain === 'All' ? undefined : domain,
        sort_by: sortBy,
        min_quality: minQuality || undefined,
        page,
        page_size: PAGE_SIZE,
      });
      setDatasets(res.data || []);
      setTotal(res.total || 0);
    } catch (e) {
      setDatasets([]);
    } finally {
      setLoading(false);
    }
  }, [search, domain, sortBy, minQuality, page]);

  useEffect(() => {
    datasetsApi.domains?.()
      .then(r => setDomainCounts(r.data || {}))
      .catch(() => {});
  }, []);

  useEffect(() => {
    const t = setTimeout(fetchData, 300);
    return () => clearTimeout(t);
  }, [fetchData]);

  const totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE));

  const resetPage = () => setPage(1);

  return (
    <div style={S.page} className="page-enter">
      {/* Sidebar */}
      <aside style={S.sidebar}>
        <div style={S.sidebarTitle}>Filters</div>

        <div style={S.filterGroup}>
          <div style={S.filterLabel}>Domain</div>
          {DOMAINS.map(d => (
            <label key={d} style={S.radio}>
              <input type="radio" name="domain" value={d} checked={domain === d}
                onChange={() => { setDomain(d); resetPage(); }} style={S.radioInput} />
              <span style={S.radioLabel}>{d}</span>
              {d !== 'All' && domainCounts[d] !== undefined &&
                <span style={S.radioCount}>{domainCounts[d]}</span>}
            </label>
          ))}
        </div>

        <div style={S.filterGroup}>
          <div style={S.filterLabel}>Sort By</div>
          <select style={S.select} value={sortBy} onChange={e => { setSortBy(e.target.value); resetPage(); }}>
            {SORT_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
          </select>
        </div>

        <div style={S.filterGroup}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
            <div style={S.filterLabel}>Min Quality</div>
            <span style={S.rangeVal}>{minQuality.toFixed(1)}+</span>
          </div>
          <div style={S.rangeWrap}>
            <input type="range" min={0} max={10} step={0.5} value={minQuality}
              onChange={e => { setMinQuality(Number(e.target.value)); resetPage(); }}
              style={S.range} />
          </div>
        </div>
      </aside>

      {/* Main */}
      <main style={S.main}>
        {/* Search */}
        <div style={S.searchBar}
          onFocus={e => { e.currentTarget.style.borderColor = 'var(--color-gold)'; e.currentTarget.style.boxShadow = 'var(--shadow-gold)'; }}
          onBlur={e => { e.currentTarget.style.borderColor = 'var(--color-stone)'; e.currentTarget.style.boxShadow = 'none'; }}>
          <span style={S.searchIcon}>🔍</span>
          <input id="explorer-search" type="text" placeholder="Search datasets..."
            value={search} onChange={e => { setSearch(e.target.value); resetPage(); }}
            style={S.searchInput} />
          {search && (
            <button onClick={() => { setSearch(''); resetPage(); }}
              style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--color-text-muted)', fontSize: '1rem' }}>
              ✕
            </button>
          )}
        </div>

        {/* Meta */}
        <div style={S.meta}>
          <span style={S.metaCount}>
            {loading ? 'Loading…' : `Showing ${datasets.length} of ${total} datasets`}
          </span>
        </div>

        {/* Grid */}
        {loading ? (
          <div style={S.grid}>
            {Array(9).fill(null).map((_, i) => <SkeletonCard key={i} />)}
          </div>
        ) : datasets.length === 0 ? (
          <div style={S.empty}>
            <div style={{ fontSize: '3rem', marginBottom: 16 }}>🗄️</div>
            <div style={{ fontWeight: 'var(--weight-semibold)', fontSize: 'var(--text-xl)', marginBottom: 8 }}>No datasets found</div>
            <div style={{ fontSize: 'var(--text-sm)', maxWidth: 300, margin: '0 auto' }}>Try adjusting your search or filters.</div>
          </div>
        ) : (
          <div style={S.grid}>
            {datasets.map(ds => {
              let tags = [];
              try { tags = JSON.parse(ds.tags); } catch { }
              return (
                <div key={ds.slug} style={S.card}
                  onClick={() => navigate(`/datasets/${ds.slug}`)}
                  onMouseEnter={e => {
                    e.currentTarget.style.borderColor = 'var(--color-gold)';
                    e.currentTarget.style.boxShadow = 'var(--shadow-md)';
                    e.currentTarget.style.transform = 'translateY(-2px)';
                  }}
                  onMouseLeave={e => {
                    e.currentTarget.style.borderColor = 'var(--color-stone)';
                    e.currentTarget.style.boxShadow = 'none';
                    e.currentTarget.style.transform = 'none';
                  }}>
                  <div style={S.cardTop}>
                    <div>
                      <div style={S.cardName}>{ds.name}</div>
                      <div style={S.cardCat}>{ds.category}</div>
                    </div>
                    <span style={{
                      padding: '2px 8px', borderRadius: 'var(--radius-full)',
                      fontSize: 'var(--text-xs)', fontWeight: 600, whiteSpace: 'nowrap', marginLeft: 8,
                      background: `${DOMAIN_COLORS[ds.domain] || '#888'}20`,
                      color: DOMAIN_COLORS[ds.domain] || '#888',
                    }}>
                      {ds.domain?.split(' ')[0]}
                    </span>
                  </div>
                  <div style={S.cardDesc}>{ds.description}</div>
                  <div style={S.cardStats}>
                    <span style={S.cardStat}>
                      <span style={{ ...S.qualDot, background: qualColor(ds.quality_score) }} />
                      {ds.quality_score?.toFixed(1)} quality
                    </span>
                    <span style={S.cardStat}>
                      📊 {ds.record_count?.toLocaleString() ?? '—'} records
                    </span>
                    <span style={S.cardStat}>🔄 {ds.sync_frequency}</span>
                  </div>
                  {tags.length > 0 && (
                    <div style={S.cardTags}>
                      {tags.slice(0, 3).map(t => (
                        <span key={t} style={{ padding: '2px 8px', background: 'var(--color-stone)', borderRadius: 'var(--radius-full)', fontSize: 10, color: 'var(--color-text-muted)' }}>
                          {t}
                        </span>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}

        {/* Pagination */}
        {totalPages > 1 && (
          <div style={S.pagination}>
            <button style={S.pageBtn} disabled={page === 1}
              onClick={() => setPage(p => p - 1)}>‹</button>
            {Array.from({ length: Math.min(7, totalPages) }, (_, i) => {
              let p = i + 1;
              if (totalPages > 7) {
                if (page <= 4) p = i + 1;
                else if (page >= totalPages - 3) p = totalPages - 6 + i;
                else p = page - 3 + i;
              }
              return (
                <button key={p} style={{ ...S.pageBtn, ...(p === page ? S.pageBtnActive : {}) }}
                  onClick={() => setPage(p)}>{p}</button>
              );
            })}
            <button style={S.pageBtn} disabled={page === totalPages}
              onClick={() => setPage(p => p + 1)}>›</button>
          </div>
        )}
      </main>
    </div>
  );
}
